change_3_optional_glob_expansion.code:
// PROP-069 Step 4: optional glob expansion for paths containing '*'
if (citation.file.includes('*')) {
  const dir = path.dirname(citation.file);
  const pattern = path.basename(citation.file).replace(/\*/g, '.*');
  const re = new RegExp('^' + pattern + '$');
  try {
    const matches = fs.readdirSync(dir).filter(f => re.test(f));
    if (matches.length > 0) {
      citation = Object.assign({}, citation, { file: path.join(dir, matches[0]), _resolved_from_glob: citation.file });
    }
  } catch (e) { /* dir missing — fall through to file_missing */ }
}

